import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import { Brain, BarChart3, MessageSquare, Upload, TrendingUp, Users } from 'lucide-react';
import axios from 'axios';
import './App.css';

// API configuration
const API_BASE_URL = 'http://localhost:5000/api';

// Components
const Navbar = () => {
  const location = useLocation();
  
  return (
    <nav className="navbar">
      <div className="navbar-content">
        <Link to="/" className="navbar-brand">
          <Brain size={24} style={{ marginRight: '8px' }} />
          Sentiment Analysis
        </Link>
        <div className="navbar-nav">
          <Link 
            to="/" 
            className={`nav-link ${location.pathname === '/' ? 'active' : ''}`}
          >
            <MessageSquare size={16} />
            Analyze
          </Link>
          <Link 
            to="/metrics" 
            className={`nav-link ${location.pathname === '/metrics' ? 'active' : ''}`}
          >
            <BarChart3 size={16} />
            Metrics
          </Link>
          <Link 
            to="/dataset" 
            className={`nav-link ${location.pathname === '/dataset' ? 'active' : ''}`}
          >
            <Upload size={16} />
            Dataset
          </Link>
        </div>
      </div>
    </nav>
  );
};

const SentimentAnalyzer = () => {
  const [text, setText] = useState('');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const analyzeSentiment = async () => {
    if (!text.trim()) {
      setError('Please enter some text to analyze');
      return;
    }

    setLoading(true);
    setError('');
    
    try {
      const response = await axios.post(`${API_BASE_URL}/predict`, {
        text: text.trim()
      });
      
      setResult(response.data);
    } catch (err) {
      setError('Failed to analyze sentiment. Please try again.');
      console.error('Error:', err);
    } finally {
      setLoading(false);
    }
  };

  const getSentimentClass = (sentiment) => {
    switch (sentiment) {
      case 'positive': return 'sentiment-positive';
      case 'negative': return 'sentiment-negative';
      case 'neutral': return 'sentiment-neutral';
      default: return '';
    }
  };

  const getSentimentIcon = (sentiment) => {
    switch (sentiment) {
      case 'positive': return '😊';
      case 'negative': return '😞';
      case 'neutral': return '😐';
      default: return '';
    }
  };

  return (
    <div className="container">
      <div className="card">
        <h2>Product Review Sentiment Analysis</h2>
        <p style={{ color: '#6c757d', marginBottom: '20px' }}>
          Enter a product review below to analyze its sentiment using our trained Naive Bayes model.
        </p>
        
        <div className="input-group">
          <label htmlFor="review-text">Review Text</label>
          <textarea
            id="review-text"
            rows="6"
            value={text}
            onChange={(e) => setText(e.target.value)}
            placeholder="Enter your product review here..."
            style={{ resize: 'vertical' }}
          />
        </div>

        <button 
          className="btn btn-primary" 
          onClick={analyzeSentiment}
          disabled={loading}
        >
          {loading ? (
            <>
              <div className="spinner"></div>
              Analyzing...
            </>
          ) : (
            <>
              <TrendingUp size={16} />
              Analyze Sentiment
            </>
          )}
        </button>

        {error && (
          <div style={{ 
            background: '#f8d7da', 
            color: '#721c24', 
            padding: '12px', 
            borderRadius: '6px', 
            marginTop: '15px' 
          }}>
            {error}
          </div>
        )}

        {result && (
          <div style={{ marginTop: '30px' }}>
            <h3>Analysis Result</h3>
            <div style={{ 
              background: '#f8f9fa', 
              padding: '20px', 
              borderRadius: '8px', 
              marginTop: '15px' 
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '15px' }}>
                <span style={{ fontSize: '1.5rem' }}>
                  {getSentimentIcon(result.sentiment)}
                </span>
                <span className={getSentimentClass(result.sentiment)}>
                  {result.sentiment.toUpperCase()}
                </span>
                <span style={{ color: '#6c757d' }}>
                  (Confidence: {(result.confidence * 100).toFixed(1)}%)
                </span>
              </div>
              
              <div>
                <h4>Confidence Breakdown:</h4>
                <div style={{ display: 'flex', gap: '15px', marginTop: '10px' }}>
                  {Object.entries(result.probabilities).map(([sentiment, prob]) => (
                    <div key={sentiment} style={{ flex: 1 }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '5px' }}>
                        <span className={getSentimentClass(sentiment)}>
                          {sentiment.charAt(0).toUpperCase() + sentiment.slice(1)}
                        </span>
                        <span>{(prob * 100).toFixed(1)}%</span>
                      </div>
                      <div className="progress-bar">
                        <div 
                          className="progress-fill" 
                          style={{ width: `${prob * 100}%` }}
                        ></div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

const ModelMetrics = () => {
  const [metrics, setMetrics] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchMetrics();
  }, []);

  const fetchMetrics = async () => {
    try {
      const response = await axios.get(`${API_BASE_URL}/metrics`);
      setMetrics(response.data.metrics);
    } catch (err) {
      setError('Failed to load metrics');
      console.error('Error:', err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="container">
        <div className="card">
          <div className="loading">
            <div className="spinner"></div>
            Loading metrics...
          </div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container">
        <div className="card">
          <div style={{ color: '#dc3545' }}>{error}</div>
        </div>
      </div>
    );
  }

  return (
    <div className="container">
      <div className="card">
        <h2>Model Performance Metrics</h2>
        <p style={{ color: '#6c757d', marginBottom: '20px' }}>
          Performance evaluation of the Naive Bayes sentiment analysis model.
        </p>

        <div className="metrics-grid">
          <div className="metric-card">
            <div className="metric-value">
              {(metrics.accuracy * 100).toFixed(1)}%
            </div>
            <div className="metric-label">Accuracy</div>
          </div>
          
          <div className="metric-card">
            <div className="metric-value">{metrics.train_size}</div>
            <div className="metric-label">Training Samples</div>
          </div>
          
          <div className="metric-card">
            <div className="metric-value">{metrics.test_size}</div>
            <div className="metric-label">Test Samples</div>
          </div>
        </div>

        {metrics.classification_report && (
          <div style={{ marginTop: '30px' }}>
            <h3>Detailed Classification Report</h3>
            <div style={{ 
              background: '#f8f9fa', 
              padding: '20px', 
              borderRadius: '8px', 
              marginTop: '15px',
              overflow: 'auto'
            }}>
              <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead>
                  <tr style={{ background: '#e9ecef' }}>
                    <th style={{ padding: '10px', textAlign: 'left' }}>Class</th>
                    <th style={{ padding: '10px', textAlign: 'right' }}>Precision</th>
                    <th style={{ padding: '10px', textAlign: 'right' }}>Recall</th>
                    <th style={{ padding: '10px', textAlign: 'right' }}>F1-Score</th>
                    <th style={{ padding: '10px', textAlign: 'right' }}>Support</th>
                  </tr>
                </thead>
                <tbody>
                  {Object.entries(metrics.classification_report).map(([key, value]) => {
                    if (key === 'accuracy' || key === 'macro avg' || key === 'weighted avg') return null;
                    return (
                      <tr key={key} style={{ borderBottom: '1px solid #dee2e6' }}>
                        <td style={{ padding: '10px', fontWeight: '600' }}>
                          {key.charAt(0).toUpperCase() + key.slice(1)}
                        </td>
                        <td style={{ padding: '10px', textAlign: 'right' }}>
                          {typeof value === 'object' ? value.precision?.toFixed(3) : 'N/A'}
                        </td>
                        <td style={{ padding: '10px', textAlign: 'right' }}>
                          {typeof value === 'object' ? value.recall?.toFixed(3) : 'N/A'}
                        </td>
                        <td style={{ padding: '10px', textAlign: 'right' }}>
                          {typeof value === 'object' ? value['f1-score']?.toFixed(3) : 'N/A'}
                        </td>
                        <td style={{ padding: '10px', textAlign: 'right' }}>
                          {typeof value === 'object' ? value.support : 'N/A'}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {metrics.confusion_matrix && (
          <div style={{ marginTop: '30px' }}>
            <h3>Confusion Matrix</h3>
            <div style={{ 
              background: '#f8f9fa', 
              padding: '20px', 
              borderRadius: '8px', 
              marginTop: '15px',
              display: 'flex',
              justifyContent: 'center'
            }}>
              <div style={{ textAlign: 'center' }}>
                <table style={{ borderCollapse: 'collapse' }}>
                  <tbody>
                    {metrics.confusion_matrix.map((row, i) => (
                      <tr key={i}>
                        {row.map((cell, j) => (
                          <td 
                            key={j}
                            style={{
                              padding: '15px',
                              border: '1px solid #dee2e6',
                              background: i === j ? '#d4edda' : '#f8d7da',
                              fontWeight: 'bold',
                              fontSize: '1.2rem'
                            }}
                          >
                            {cell}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
                <div style={{ marginTop: '10px', fontSize: '0.9rem', color: '#6c757d' }}>
                  Rows: Actual, Columns: Predicted
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

const DatasetViewer = () => {
  const [dataset, setDataset] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchDataset();
  }, []);

  const fetchDataset = async () => {
    try {
      const response = await axios.get(`${API_BASE_URL}/sample-dataset`);
      setDataset(response.data.dataset);
    } catch (err) {
      setError('Failed to load dataset');
      console.error('Error:', err);
    } finally {
      setLoading(false);
    }
  };

  const getSentimentClass = (sentiment) => {
    switch (sentiment) {
      case 'positive': return 'sentiment-positive';
      case 'negative': return 'sentiment-negative';
      case 'neutral': return 'sentiment-neutral';
      default: return '';
    }
  };

  if (loading) {
    return (
      <div className="container">
        <div className="card">
          <div className="loading">
            <div className="spinner"></div>
            Loading dataset...
          </div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container">
        <div className="card">
          <div style={{ color: '#dc3545' }}>{error}</div>
        </div>
      </div>
    );
  }

  return (
    <div className="container">
      <div className="card">
        <h2>Sample Dataset</h2>
        <p style={{ color: '#6c757d', marginBottom: '20px' }}>
          This is the sample dataset used to train the sentiment analysis model. 
          The dataset contains product reviews with their corresponding sentiment labels.
        </p>

        <div style={{ 
          background: '#f8f9fa', 
          padding: '20px', 
          borderRadius: '8px',
          maxHeight: '600px',
          overflow: 'auto'
        }}>
          <div style={{ display: 'grid', gap: '15px' }}>
            {dataset.map((item, index) => (
              <div 
                key={index}
                style={{ 
                  background: 'white', 
                  padding: '15px', 
                  borderRadius: '6px',
                  border: '1px solid #dee2e6'
                }}
              >
                <div style={{ marginBottom: '10px' }}>
                  <span className={getSentimentClass(item.sentiment)}>
                    {item.sentiment.toUpperCase()}
                  </span>
                </div>
                <div style={{ fontSize: '0.95rem', lineHeight: '1.5' }}>
                  "{item.review}"
                </div>
              </div>
            ))}
          </div>
        </div>

        <div style={{ 
          marginTop: '20px', 
          padding: '15px', 
          background: '#e7f3ff', 
          borderRadius: '6px',
          border: '1px solid #b8daff'
        }}>
          <strong>Dataset Statistics:</strong>
          <ul style={{ marginTop: '10px', paddingLeft: '20px' }}>
            <li>Total Reviews: {dataset.length}</li>
            <li>Positive Reviews: {dataset.filter(item => item.sentiment === 'positive').length}</li>
            <li>Negative Reviews: {dataset.filter(item => item.sentiment === 'negative').length}</li>
            <li>Neutral Reviews: {dataset.filter(item => item.sentiment === 'neutral').length}</li>
          </ul>
        </div>
      </div>
    </div>
  );
};

const App = () => {
  return (
    <Router>
      <div className="App">
        <Navbar />
        <Routes>
          <Route path="/" element={<SentimentAnalyzer />} />
          <Route path="/metrics" element={<ModelMetrics />} />
          <Route path="/dataset" element={<DatasetViewer />} />
        </Routes>
      </div>
    </Router>
  );
};

export default App;
